from flask import Flask, request, jsonify
from selenium import webdriver
from selenium.webdriver.chrome.service import Service
from selenium.webdriver.chrome.options import Options
from webdriver_manager.chrome import ChromeDriverManager
import boto3
import re
import os
import socket

app = Flask(__name__)
s3_client = boto3.client('s3')
BUCKET_NAME = 'your-s3-bucket-name'

ALLOWED_DOMAINS = ['example.com', 'another-example.com']
URL_REGEX = re.compile(r'^(http|https)://')

def is_valid_url(url):
    if not URL_REGEX.match(url):
        return False
    domain = url.split('/')[2]
    if not any(domain.endswith(allowed) for allowed in ALLOWED_DOMAINS):
        return False
    try:
        ip = socket.gethostbyname(domain)
        if ip.startswith(('10.', '172.', '192.168.')):
            return False
    except socket.error:
        return False
    return True

@app.route('/screenshot', methods=['POST'])
def screenshot():
    data = request.json
    url = data.get('url')

    if not is_valid_url(url):
        return jsonify({'error': 'Invalid URL'}), 400

    options = Options()
    options.headless = True
    service = Service(ChromeDriverManager().install())
    driver = webdriver.Chrome(service=service, options=options)

    try:
        driver.get(url)
        screenshot_path = '/tmp/screenshot.png'
        driver.save_screenshot(screenshot_path)

        s3_client.upload_file(screenshot_path, BUCKET_NAME, 'screenshot.png')
        os.remove(screenshot_path)

        return jsonify({'message': 'Screenshot taken', 'url': f'https://{BUCKET_NAME}.s3.amazonaws.com/screenshot.png'}), 200
    finally:
        driver.quit()

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)